-- =========================
-- DROP + CREATE RESEARCH KPI TABLE
-- =========================

DROP TABLE IF EXISTS research_kpis CASCADE;

CREATE TABLE research_kpis (
  id SERIAL PRIMARY KEY,
  institution_id INTEGER REFERENCES institutions(id),
  academic_year VARCHAR(10),
  publications_count INTEGER,
  active_projects INTEGER,
  funding_secured_tnd DECIMAL(12,2),
  phd_students INTEGER,
  patents_filed INTEGER,
  international_collaborations INTEGER,
  national_collaborations INTEGER,
  conferences_attended INTEGER,
  recorded_at TIMESTAMP DEFAULT NOW()
);

